CREATE DATABASE IF NOT EXISTS gestion_cuotas CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci;
USE gestion_cuotas;

CREATE TABLE migrations (
  id BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY,
  version VARCHAR(20) NOT NULL UNIQUE,
  nombre_archivo VARCHAR(255) NOT NULL,
  fecha_ejecucion TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP,
  ejecutado_por VARCHAR(100) NULL,
  observacion VARCHAR(255) NULL
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;

CREATE TABLE roles (id BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY,nombre VARCHAR(60) UNIQUE,descripcion VARCHAR(255),activo TINYINT(1) DEFAULT 1,created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,updated_at TIMESTAMP NULL ON UPDATE CURRENT_TIMESTAMP) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;
CREATE TABLE usuarios (id BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY,nombre VARCHAR(120),correo VARCHAR(120) UNIQUE,usuario VARCHAR(60) UNIQUE,password VARCHAR(255),rol_id BIGINT UNSIGNED,activo TINYINT(1) DEFAULT 1,ultimo_acceso DATETIME NULL,created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,updated_at TIMESTAMP NULL ON UPDATE CURRENT_TIMESTAMP,FOREIGN KEY (rol_id) REFERENCES roles(id)) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;
CREATE TABLE tipos_socio (id BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY,nombre VARCHAR(80) UNIQUE,activo TINYINT(1) DEFAULT 1) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;
CREATE TABLE estados_socio (id BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY,nombre VARCHAR(80) UNIQUE,activo TINYINT(1) DEFAULT 1) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;
CREATE TABLE socios (id BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY,numero_socio VARCHAR(30) UNIQUE,rut VARCHAR(30) UNIQUE,nombres VARCHAR(120),apellidos VARCHAR(120),nombre_completo VARCHAR(240),fecha_nacimiento DATE NULL,telefono VARCHAR(50),correo VARCHAR(120),direccion VARCHAR(255),comuna VARCHAR(120),ciudad VARCHAR(120),tipo_socio_id BIGINT UNSIGNED,estado_socio_id BIGINT UNSIGNED,fecha_ingreso DATE,observaciones TEXT NULL,activo TINYINT(1) DEFAULT 1,created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,updated_at TIMESTAMP NULL ON UPDATE CURRENT_TIMESTAMP,deleted_at TIMESTAMP NULL,INDEX idx_socios_nombre(nombre_completo),INDEX idx_socios_rut(rut),FOREIGN KEY (tipo_socio_id) REFERENCES tipos_socio(id),FOREIGN KEY (estado_socio_id) REFERENCES estados_socio(id)) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;
CREATE TABLE periodos (id BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY,nombre_periodo VARCHAR(100) NOT NULL,tipo_periodo ENUM('mensual','trimestral','semestral','anual') NOT NULL,monto_a_pagar DECIMAL(12,2) NOT NULL DEFAULT 0,anio SMALLINT NULL,mes TINYINT NULL,fecha_inicio DATE NULL,fecha_fin DATE NULL,fecha_vencimiento DATE NULL,cerrado TINYINT(1) DEFAULT 0,observacion VARCHAR(255) NULL,created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,updated_at TIMESTAMP NULL ON UPDATE CURRENT_TIMESTAMP) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;
CREATE TABLE socio_planes (id BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY,socio_id BIGINT UNSIGNED NOT NULL,periodo_id BIGINT UNSIGNED NOT NULL,created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,UNIQUE KEY uk_socio_plan(socio_id,periodo_id),FOREIGN KEY (socio_id) REFERENCES socios(id),FOREIGN KEY (periodo_id) REFERENCES periodos(id)) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;
CREATE TABLE conceptos_cobro (id BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY,nombre VARCHAR(100) UNIQUE,descripcion VARCHAR(255),activo TINYINT(1) DEFAULT 1,monto_sugerido DECIMAL(12,2) NULL) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;
CREATE TABLE cuotas (id BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY,socio_id BIGINT UNSIGNED,periodo_id BIGINT UNSIGNED,concepto_cobro_id BIGINT UNSIGNED,monto_base DECIMAL(12,2),saldo_arrastre DECIMAL(12,2) DEFAULT 0,monto_total DECIMAL(12,2),monto_pagado DECIMAL(12,2) DEFAULT 0,saldo_pendiente DECIMAL(12,2),estado_cuota ENUM('pendiente','abonada_parcial','pagada','vencida','exenta','anulada') DEFAULT 'pendiente',fecha_vencimiento DATE,observacion VARCHAR(255) NULL,generada_automaticamente TINYINT(1) DEFAULT 1,created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,updated_at TIMESTAMP NULL ON UPDATE CURRENT_TIMESTAMP,deleted_at TIMESTAMP NULL,INDEX idx_cuotas_estado(estado_cuota),FOREIGN KEY (socio_id) REFERENCES socios(id),FOREIGN KEY (periodo_id) REFERENCES periodos(id),FOREIGN KEY (concepto_cobro_id) REFERENCES conceptos_cobro(id)) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;
CREATE TABLE medios_pago (id BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY,nombre VARCHAR(60) UNIQUE,activo TINYINT(1) DEFAULT 1) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;
CREATE TABLE cuentas_bancarias (id BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY,banco VARCHAR(120),tipo_cuenta VARCHAR(60),numero_cuenta VARCHAR(60),titular VARCHAR(120),correo_asociado VARCHAR(120),activa TINYINT(1) DEFAULT 1,saldo_inicial DECIMAL(12,2) DEFAULT 0,created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;
CREATE TABLE pagos (id BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY,socio_id BIGINT UNSIGNED,fecha_pago DATE,monto_total DECIMAL(12,2),medio_pago_id BIGINT UNSIGNED,cuenta_bancaria_id BIGINT UNSIGNED NULL,numero_comprobante VARCHAR(60),referencia_externa VARCHAR(100) NULL,observacion VARCHAR(255) NULL,periodo_a_pagar VARCHAR(140) NULL,estado_pago ENUM('aplicado','anulado','pendiente_revision') DEFAULT 'aplicado',usuario_id BIGINT UNSIGNED,created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,updated_at TIMESTAMP NULL ON UPDATE CURRENT_TIMESTAMP,deleted_at TIMESTAMP NULL,INDEX idx_pago_fecha(fecha_pago),FOREIGN KEY (socio_id) REFERENCES socios(id),FOREIGN KEY (medio_pago_id) REFERENCES medios_pago(id),FOREIGN KEY (cuenta_bancaria_id) REFERENCES cuentas_bancarias(id),FOREIGN KEY (usuario_id) REFERENCES usuarios(id)) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;
CREATE TABLE pago_detalle (id BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY,pago_id BIGINT UNSIGNED,cuota_id BIGINT UNSIGNED,monto_aplicado DECIMAL(12,2),created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,FOREIGN KEY (pago_id) REFERENCES pagos(id),FOREIGN KEY (cuota_id) REFERENCES cuotas(id)) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;
CREATE TABLE tipos_aporte (id BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY,nombre VARCHAR(80) UNIQUE,activo TINYINT(1) DEFAULT 1) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;
CREATE TABLE aportes (id BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY,socio_id BIGINT UNSIGNED NULL,nombre_aportante VARCHAR(140),tipo_aporte_id BIGINT UNSIGNED,fecha_aporte DATE,monto DECIMAL(12,2),descripcion VARCHAR(255),comentario VARCHAR(255) NULL,comprobante VARCHAR(255),observacion VARCHAR(255) NULL,usuario_id BIGINT UNSIGNED,estado ENUM('aplicado','anulado','pendiente_revision') DEFAULT 'aplicado',created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,updated_at TIMESTAMP NULL ON UPDATE CURRENT_TIMESTAMP,FOREIGN KEY (socio_id) REFERENCES socios(id),FOREIGN KEY (tipo_aporte_id) REFERENCES tipos_aporte(id),FOREIGN KEY (usuario_id) REFERENCES usuarios(id)) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;
CREATE TABLE tipos_egreso (id BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY,nombre VARCHAR(80) UNIQUE,activo TINYINT(1) DEFAULT 1) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;
CREATE TABLE egresos (id BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY,fecha DATE,tipo_egreso_id BIGINT UNSIGNED,descripcion VARCHAR(255),monto DECIMAL(12,2),numero_documento VARCHAR(80),proveedor_destinatario VARCHAR(120),cuenta_bancaria_id BIGINT UNSIGNED NULL,observacion VARCHAR(255) NULL,usuario_id BIGINT UNSIGNED,estado ENUM('aplicado','anulado','pendiente_revision') DEFAULT 'aplicado',created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,updated_at TIMESTAMP NULL ON UPDATE CURRENT_TIMESTAMP,deleted_at TIMESTAMP NULL,FOREIGN KEY (tipo_egreso_id) REFERENCES tipos_egreso(id),FOREIGN KEY (cuenta_bancaria_id) REFERENCES cuentas_bancarias(id),FOREIGN KEY (usuario_id) REFERENCES usuarios(id)) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;
CREATE TABLE rendiciones (id BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY,numero_rendicion VARCHAR(60) UNIQUE,fecha_desde DATE,fecha_hasta DATE,descripcion VARCHAR(255),monto_total DECIMAL(12,2),estado ENUM('abierta','cerrada') DEFAULT 'abierta',observacion VARCHAR(255) NULL,usuario_id BIGINT UNSIGNED,created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,updated_at TIMESTAMP NULL ON UPDATE CURRENT_TIMESTAMP,FOREIGN KEY (usuario_id) REFERENCES usuarios(id)) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;
CREATE TABLE rendicion_detalle (id BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY,rendicion_id BIGINT UNSIGNED,egreso_id BIGINT UNSIGNED,FOREIGN KEY (rendicion_id) REFERENCES rendiciones(id),FOREIGN KEY (egreso_id) REFERENCES egresos(id)) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;
CREATE TABLE movimientos_tesoreria (id BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY,cuenta_bancaria_id BIGINT UNSIGNED NULL,fecha DATE,tipo_movimiento ENUM('ingreso','egreso'),origen_modulo VARCHAR(80),referencia_id BIGINT UNSIGNED,descripcion VARCHAR(255),ingreso DECIMAL(12,2) DEFAULT 0,egreso DECIMAL(12,2) DEFAULT 0,saldo_referencial DECIMAL(12,2) DEFAULT 0,created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,FOREIGN KEY (cuenta_bancaria_id) REFERENCES cuentas_bancarias(id)) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;
CREATE TABLE configuracion (id BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY,nombre_organizacion VARCHAR(140),nombre_sistema VARCHAR(140),logo VARCHAR(255) NULL,rut_organizacion VARCHAR(30) NULL,direccion VARCHAR(255),telefono VARCHAR(40),correo VARCHAR(120),sitio_web VARCHAR(120) NULL,flow_api_key VARCHAR(120) NULL,flow_secret_key VARCHAR(140) NULL,flow_modo_sandbox TINYINT(1) DEFAULT 1,cuota_por_defecto DECIMAL(12,2) DEFAULT 0,moneda VARCHAR(20) DEFAULT 'CLP',simbolo_moneda VARCHAR(5) DEFAULT '$',texto_comprobante TEXT,observaciones_generales TEXT NULL,updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;
CREATE TABLE auditoria (id BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY,usuario_id BIGINT UNSIGNED NULL,modulo VARCHAR(80),accion VARCHAR(80),id_registro BIGINT UNSIGNED NULL,datos_anteriores JSON NULL,datos_nuevos JSON NULL,fecha TIMESTAMP DEFAULT CURRENT_TIMESTAMP,ip VARCHAR(45),user_agent VARCHAR(255) NULL,FOREIGN KEY (usuario_id) REFERENCES usuarios(id)) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;
